import React from "react"
import Select from 'react-select'
import { properties } from '../../properties/properties.js'
import querystring from 'query-string'
import { Chart as ChartJS, registerables } from 'chart.js';
import { Bar } from 'react-chartjs-2'
ChartJS.register(...registerables);

class Report extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0
        };
    }







      componentDidMount() {



        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `getVoalteFamily`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})
            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });

      }






          render() {


            var header = "Loading ..."




            if (this.state.screen === 1) {
              header = ""
              var content = []



                this.state.results.family.map(rec => {

                    content.push(<div><hr></hr><h2>{rec.unit}</h2></div>)


                    var dataset = []
                    var datasetPatient = []
                    var i = 0
                    var colorBar = ["blue", "green", "orange", "red"]

                  var tableContent = []

                  var tableStyle = {
                    "border": "1px solid black"
                 };

                    rec.data.map(rec2 => {

                        var totalMessage = parseInt(rec2.totalmessage)
                        var familyMembersEnrolled = parseInt(rec2.familymembersenrolled)
                        var uniquePatients = parseInt(rec2.uniquepatients)
                        var uniqueMsgPatients = parseInt(rec2.uniquemsgpatients)
                        var uniqueFamilyPatients = parseInt(rec2.uniquefamilypatients)

                        var admits = 0
                        var census = 0

                        var censusResult = []
                        var patientResult = []

                        if (rec.unit != "all") {
                          censusResult = this.state.results.census.filter(rec3 => rec3.year == rec2.year && rec3.month == rec2.month && rec3.unit == rec.unit)
                          patientResult = this.state.results.patientExperience.filter(rec5 => rec5.year == rec2.year && rec5.month == rec2.month && rec5.unit == rec.unit)
                        } else {
                          censusResult = this.state.results.census.filter(rec3 => rec3.year == rec2.year && rec3.month == rec2.month)
                          patientResult = this.state.results.patientExperience.filter(rec5 => rec5.year == rec2.year && rec5.month == rec2.month)
                        }

                        censusResult.map(rec4 => {
                          admits += rec4.admits
                          census += rec4.census
                        })

                        var score1 = 0
                        var score2 = 0
                        var score3 = 0
                        var score4 = 0


                        patientResult.map(recP => {
                          if (recP.id == 1) {
                            score1 += recP.score
                          }
                          if (recP.id == 2) {
                            score2 += recP.score
                          }
                          if (recP.id == 3) {
                            score3 += recP.score
                          }
                          if (recP.id == 4) {
                            score4 += recP.score
                          }
                        })


                        var graphData = []
                        var graphPatientData = []

                        graphPatientData.push(score1)
                        graphPatientData.push(score2)
                        graphPatientData.push(score3)
                        graphPatientData.push(score4)

                        graphData.push(admits)
                        graphData.push(census)
                        graphData.push(totalMessage)
                        graphData.push(familyMembersEnrolled)
                        graphData.push(uniqueFamilyPatients)

                        var avgMessage = 0
                        if (uniqueMsgPatients == 0) {
                            graphData.push(0)
                        } else {
                            avgMessage = totalMessage / uniqueMsgPatients
                            graphData.push(totalMessage / uniqueMsgPatients)
                        }
                        graphData.push(uniquePatients)


                        dataset.push({label: rec2.month + "/" + rec2.year, data: graphData, backgroundColor: colorBar[i%4]})
                        datasetPatient.push({label: rec2.month + "/" + rec2.year, data: graphPatientData, backgroundColor: colorBar[i%4]})


                        tableContent.push(<tr><tb style={tableStyle}>{rec2.month+"/"+rec2.year}</tb><td style={tableStyle}>{admits}</td><td style={tableStyle}>{census}</td><td style={tableStyle}>{totalMessage}</td><td style={tableStyle}>{familyMembersEnrolled}</td><td style={tableStyle}>{uniqueFamilyPatients}</td><td style={tableStyle}>{avgMessage}</td><td style={tableStyle}>{uniquePatients}</td></tr>)

                        i += 1
                    })




                    content.push(<div><Bar 
                        height={400} 
                        width={400} 
                        data={{
                          labels: ["Total Admits", "Census", "Total Messages and Photos", "Voalte Family Members Enrolled", "Voalte Family Patients active during the month", "Average Messages Per Patient","Voalte Family Newly enrolled Patients"],
                          datasets: dataset


                        }} 
                        options={{maintainAspectRatio: false}}

                        ></Bar></div>)


                      content.push(<div><br></br><table><tr><td style={tableStyle}></td><td style={tableStyle}>Total Admits</td><td style={tableStyle}>Census</td><td style={tableStyle}>Total Messages and Photos</td><td style={tableStyle}>Voalte Family Members Enrolled</td><td style={tableStyle}>Voalte Family Patients active during the month</td><td style={tableStyle}>Average Messages Per Patient</td><td style={tableStyle}>Voalte Family Newly enrolled Patients</td></tr>{tableContent}</table></div>)




                      content.push(<div><div>Patient Experience</div><Bar 
                        height={400} 
                        width={400} 
                        data={{
                          labels: ["Confidence and trust in nurses", "Comfort talking with nurse", "Received consistent info", "Facility would recommend"],
                          datasets: datasetPatient


                        }} 
                        options={{maintainAspectRatio: false}}

                        ></Bar></div>)





                })










          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Report
